#include<bits/stdc++.h>
using namespace std;
int a[3001],dp[3001][3001][2];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0][0][0]=0;
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<=m;j++)
        {
            if(dp[i][j][0]!=0x3f3f3f3f)
            {
                dp[i+1][j][1]=min(dp[i+1][j][1],dp[i][j][0]+1);
                if(j+a[i+1]<=m)
                {
                    dp[i+1][j+a[i+1]][0]=min(dp[i+1][j+a[i+1]][0],dp[i][j][0]);
                }
            }
            if(dp[i][j][1]!=0x3f3f3f3f)
            {
                dp[i+1][j][1]=min(dp[i+1][j][1],dp[i][j][1]);
                if(j+a[i+1]<=m)
                {
                    dp[i+1][j+a[i+1]][0]=min(dp[i+1][j+a[i+1]][0],dp[i][j][1]);
                }
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        int ans=min(dp[n][i][0],dp[n][i][1]);
        if(ans==0x3f3f3f3f)
        {
            printf("-1");
        }
        else
        {
            printf("%d",ans);
        }
        printf("\n");
    }
    return 0;
}
